function counting_sort(array A):
    let n = length(A)
    let k = maximum value in A

    create count[0..k] initialized to 0

    for each element x in A:
        count[x] += 1

    create output array B of size n
    index = 0
    for value from 0 to k:
        while count[value] > 0:
            B[index] = value
            index += 1
            count[value] -= 1

    return B

def median_of_medians(A, i):

    #divide A into sublists of len 5
    sublists = [A[j:j+5] for j in range(0, len(A), 5)]
    medians = [sorted(sublist)[len(sublist)/2] for sublist in sublists]
    if len(medians) <= 5:
        pivot = sorted(medians)[len(medians)/2]
    else:
        #the pivot is the median of the medians
        pivot = median_of_medians(medians, len(medians)/2)

    #partitioning step
    low = [j for j in A if j < pivot]
    high = [j for j in A if j > pivot]

    k = len(low)
    if i < k:
        return median_of_medians(low,i)
    elif i > k:
        return median_of_medians(high,i-k-1)
    else: #pivot = k
        return pivot

procedure insertionSort(array A)
    n = length(A)
    // Iterate from the second element to the last
    for i = 1 to n - 1
        // Store the current element to be inserted
        key = A[i]
        // Start comparing key with elements to its left
        j = i - 1

        // Move elements of A[0..i-1], that are greater than key, 
        // to one position ahead of their current position
        while j >= 0 and A[j] > key
            A[j + 1] = A[j]
            j = j - 1

        // Insert the key into its correct position
        A[j + 1] = key
    end for
end procedure

